INSERT INTO public.complaints (id, user_id, order_id, product_code, issue_type, severity, complaint, status, resolution, created_at, updated_at, version) VALUES (1, 'eburke', 914, '101759', 'defect', 'critical', 'Sharp edge was exposed after the product failed during use. Cut myself badly and required medical attention.', 'open', 'replacement', '2026-03-30 13:47:48.908', '2026-03-30 13:47:48.908', 1);
INSERT INTO public.complaints (id, user_id, order_id, product_code, issue_type, severity, complaint, status, resolution, created_at, updated_at, version) VALUES (2, 'cchang2', 1396, '101759', 'defect', 'critical', 'Product failure caused significant damage to other property around it. This represents a major quality control failure.', 'open', 'refund', '2026-03-11 03:21:50.277', '2026-03-11 03:21:50.277', 1);
INSERT INTO public.complaints (id, user_id, order_id, product_code, issue_type, severity, complaint, status, resolution, created_at, updated_at, version) VALUES (3, 'cavila', 1944, '101759', 'quality', 'high', 'Quality control was obviously severely lacking. Received a clearly defective unit that shouldn''t have shipped.', 'in_progress', 'replacement', '2026-03-12 10:51:01.570', '2026-03-12 10:51:01.570', 1);
INSERT INTO public.complaints (id, user_id, order_id, product_code, issue_type, severity, complaint, status, resolution, created_at, updated_at, version) VALUES (4, 'arobinson', 2083, '101759', 'defect', 'high', 'Major manufacturing defect makes the product barely functional at all. Cannot perform its primary purpose reliably.', 'in_progress', 'refund', '2026-03-11 06:06:16.319', '2026-03-11 06:06:16.319', 1);
INSERT INTO public.complaints (id, user_id, order_id, product_code, issue_type, severity, complaint, status, resolution, created_at, updated_at, version) VALUES (5, 'gmclaughlin', 1158, '101759', 'defect', 'low', 'Minor difficulty during assembly that shouldn''t have been an issue. Design could be more user-friendly.', 'open', 'refund', '2026-03-28 02:02:13.671', '2026-03-28 02:02:13.671', 1);
INSERT INTO public.complaints (id, user_id, order_id, product_code, issue_type, severity, complaint, status, resolution, created_at, updated_at, version) VALUES (6, 'gvaughn', 999, '101759', 'defect', 'medium', 'Assembly was required but the instructions were unclear and confusing. Took much longer than it should have.', 'in_progress', 'refund', '2026-03-31 21:20:58.326', '2026-03-31 21:20:58.326', 1);
INSERT INTO public.complaints (id, user_id, order_id, product_code, issue_type, severity, complaint, status, resolution, created_at, updated_at, version) VALUES (7, 'cjones', 2029, '101759', 'quality', 'high', 'Finish is peeling off completely from the surface. Now it looks terrible and damaged after minimal use.', 'open', 'replacement', '2026-03-10 18:08:33.789', '2026-03-10 18:08:33.789', 1);
INSERT INTO public.complaints (id, user_id, order_id, product_code, issue_type, severity, complaint, status, resolution, created_at, updated_at, version) VALUES (8, 'rflores', 1709, '101759', 'quality', 'critical', 'Serious safety hazard as it broke in a dangerous way during normal use. Someone could easily be injured by this failure.', 'open', 'replacement', '2026-02-04 16:56:15.455', '2026-02-04 16:56:15.455', 1);
